function getEditionAgents(){
  if(!EDITION_KEY || !EDITIONS[EDITION_KEY]) return AGENTS;
  const {ids}=EDITIONS[EDITION_KEY];
  return AGENTS.filter(a=>ids.has(a.id));
}

function applyEdition(){
  const ed=EDITIONS[EDITION_KEY]; if(!ed) return;
  document.querySelector('.logo').innerHTML=ed.brand;
  document.title=ed.title;
  document.documentElement.style.setProperty('--accent',ed.accent);
  document.documentElement.style.setProperty('--accent2',ed.accent2);
  const s=document.getElementById('search'); if(s) s.placeholder=ed.placeholder;
  // Edition pill in header
  const pill=document.createElement('span');
  pill.style.cssText=`font-size:10px;background:${ed.accent}33;border:1px solid ${ed.accent}66;color:${ed.accent2};padding:2px 9px;border-radius:99px;font-weight:700;flex-shrink:0`;
  pill.textContent=ed.tagline;
  const hdrDot=document.getElementById('hdr-dot');
  hdrDot.parentNode.insertBefore(pill,hdrDot.nextSibling);
  // Back link
  const back=document.createElement('button');
  back.className='icon-btn'; back.style.cssText='font-size:11px;padding:4px 8px';
  back.textContent='← All'; back.title='Back to AgentForge';
  back.onclick=()=>{const u=new URL(location.href);u.searchParams.delete('edition');location.href=u.toString();};
  document.querySelector('.hdr-right').prepend(back);
}

